#!/bin/bash
set -e
MOUNT=$(docker inspect supabase-edge-functions --format '{{range .Mounts}}{{.Source}}{{println}}{{end}}' | grep functions | head -1)
echo "MOUNT_SOURCE=$MOUNT"
DIR=/root/supabase-docker/volumes/functions/analyze-prompt-improvement
echo "BEFORE: $(ls $DIR | wc -l) files"
echo "" | base64 -d > $DIR/claude.ts
echo "" | base64 -d > $DIR/index.ts
echo "AFTER: $(ls $DIR | wc -l) files"
md5sum $DIR/claude.ts $DIR/index.ts
docker restart $(docker ps --filter name=supabase-edge-functions -q) >/dev/null
sleep 5
docker exec supabase-edge-functions md5sum /home/deno/functions/analyze-prompt-improvement/claude.ts /home/deno/functions/analyze-prompt-improvement/index.ts
docker exec supabase-edge-functions ls /home/deno/functions/analyze-prompt-improvement | wc -l
echo DEPLOY_DONE
